import test from 'node:test';
import assert from 'node:assert/strict';
import { parseMarkdownTable } from './table.js';

test('parses basic table', () => {
  assert.deepEqual(parseMarkdownTable(`
| name | age |
| --- | ---: |
| Ada | 36 |
| Linus | 56 |
`), [
    { name: 'Ada', age: '36' },
    { name: 'Linus', age: '56' }
  ]);
});

test('preserves empty cells and handles missing outer pipes', () => {
  assert.deepEqual(parseMarkdownTable(`
name | age | city
--- | --- | ---
Ada |  | London
Bob | 42 |
`), [
    { name: 'Ada', age: '', city: 'London' },
    { name: 'Bob', age: '42', city: '' }
  ]);
});

test('supports escaped pipe characters in cells', () => {
  assert.deepEqual(parseMarkdownTable(`
| package | description |
| --- | --- |
| a \| b | contains a pipe |
`), [
    { package: 'a | b', description: 'contains a pipe' }
  ]);
});

test('ignores blank lines before and after table', () => {
  assert.deepEqual(parseMarkdownTable(`

| k | v |
| --- | --- |
| x | y |

`), [{ k: 'x', v: 'y' }]);
});

test('throws for malformed tables', () => {
  assert.throws(() => parseMarkdownTable('not a table'), SyntaxError);
  assert.throws(() => parseMarkdownTable('| a | b |\n| --- |\n| 1 | 2 |'), SyntaxError);
});
